import axios from 'axios';
import { useEffect, useState } from 'react';

function Home() {
  const [cas, setCas] = useState([]);

  useEffect(() => {
    axios.get('http://localhost:5001/api/ca')
      .then(res => setCas(res.data));
  }, []);

  return (
    <div>
      <h1>Top Chartered Accountants</h1>
      {cas.map(ca => (
        <div key={ca._id}>
          <h3>{ca.name}</h3>
          <p>Experience: {ca.experience} years</p>
          <p>Subscribers: {ca.subscribersCount}</p>
        </div>
      ))}
    </div>
  );
}

export default Home;
